// Preprocess input: extract code, language, filename, context
const body = $input.first().json.body || $input.first().json;
const code = body.code || '';
const language = body.language || 'typescript';
const filename = body.filename || `review.${language}`;
const context = body.context || '';

if (!code.trim()) {
  throw new Error('No code provided');
}

return [{
  json: {
    code,
    language,
    filename,
    context,
    receivedAt: new Date().toISOString()
  }
}];

// Parse SSE stream from backend and extract the review:completed event
const raw = $input.first().json.data || '';
let result = null;

const chunks = raw.split('\n\n');
for (const chunk of chunks) {
  const lines = chunk.split('\n');
  let eventType = '';
  let dataStr = '';
  for (const line of lines) {
    if (line.startsWith('event: ')) eventType = line.slice(7).trim();
    if (line.startsWith('data: ')) dataStr = line.slice(6).trim();
  }
  if (eventType === 'review:completed' && dataStr) {
    try { result = JSON.parse(dataStr); } catch {}
  }
}

if (!result) {
  return [{ json: { error: 'No review result found in stream', raw: raw.slice(0, 500) } }];
}

return [{ json: result }];

